catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
	if (isLoading) {
		return;
	}

	if (newValue == "") {
		// 全項目の値をクリア
		g_form.clearValue("work_app_type");
		g_form.clearValue("reason");
		g_form.clearValue("is_coordinated");
		g_form.clearValue("target_date");
		g_form.clearValue("start_time");
		g_form.clearValue("end_time");
		g_form.clearValue("worked_day");
		g_form.clearValue("replacement_holiday");
		g_form.clearValue("remarks");
		g_form.clearValue("approver");
	} else {
		// 過去の申請情報を取得し、各項目へ反映
		var ga = new GlideAjax("x_1447708_dottctmp.DOTTCTMPUtils");
		ga.addParam("sysparm_name", "getPastAppInfo");
		ga.addParam("sysparm_sysId", newValue);
		ga.getXMLAnswer(cb);
	}

}

function cb(answer) {
	answer = JSON.parse(answer);
	var questions = [
		"work_app_type",
		"reason",
		"is_coordinated",
		"target_date",
		"start_time",
		"end_time",
		"worked_day",
		"start_working_time",
		"end_working_time",
		"worked_day",
		"replacement_holiday",
		"remarks",
		"approver"
	];

	for (var question of questions) {
		g_form.setValue(question, answer[question]);
	}
}
